<template>
  <div>
    <!-- <v-card style="width:100%;" class="d-inline-block mx-auto"> -->
    <!-- <v-container> -->
    <!-- <div style="margin-bottom:10px;">バックアップ・リストア</div> -->
    <!-- <div>DBバックアップ</div> -->
    <!-- <button v-on:click="onClickBackupDB" class="btn btn-primary">DBバックアップ</button> -->
    <v-btn v-on:click="onClickBackupDB" color="primary" dark>DBバックアップ</v-btn>
    <!-- <br /> -->
    <div style="margin-bottom:30px;">前回バックアップ日時 : {{ bkDate }}</div>
    <!-- <div>DBリストア</div> -->
    <!-- <button v-on:click="onClickRestoreDB" class="btn btn-warning">DBリストア</button> -->
    <v-btn style="margin-bottom:30px;" v-on:click="onClickRestoreDB" color="warning" dark>DBリストア</v-btn>
    <br />

    <!-- <div>DB内容JSON出力</div> -->
    <!-- <button v-on:click="outputDB" class="btn btn-primary">出力</button> -->
    <v-btn v-on:click="outputDB" color="primary" dark>DB内容JSON出力</v-btn>
    <!-- <textarea style="margin-bottom:30px;width:100%;height:300px;" v-model="output"></textarea> -->
    <v-textarea style="margin-top:10px;" outlined label="JSON" v-model="output"></v-textarea>
    <!-- <button v-on:click="onClickInputDB" class="btn btn-warning">入力</button> -->
    <!-- <div>DB内容JSON入力</div> -->
    <v-form v-model="isFormValid" ref="score_json_input_form">
      <v-btn v-on:click="onClickInputDB" color="warning" dark>DB内容JSON入力</v-btn>
      <!-- <textarea style="width:100%;height:300px;" v-model="modelInput"></textarea> -->
      <v-textarea
        style="margin:10px 0;"
        outlined
        label="JSON"
        v-model="modelInput"
        v-bind:rules="[required]"
      ></v-textarea>
    </v-form>

    <v-btn v-on:click="onClickClear" color="warning" dark>DB消去</v-btn>

    <confirm ref="confirm"></confirm>
    <!-- </v-container> -->
    <!-- </v-card> -->
  </div>
</template>

<script>
import confirm from "./Confirm";

export default {
  name: "backup",
  components: {
    confirm
  },
  data() {
    return {
      dialogProp: {
        title: "",
        msg: "",
        positive: "",
        negative: "",
        callback: null
      },
      isFormValid: true,
      required: value => !!value || "必須入力",
      output: "",
      modelInput: "",
      // showModalConfirm: false,
      // title: "",
      // msg: "",
      // positive: "OK",
      // negative: "キャンセル",
      // callbackConfirm: null,
      bkDate: ""
    };
  },
  computed: {
    // compMessage() {
    //     return this.modelA + this.modelB;
    // }
  },
  mounted() {
    var bkDate = localStorage.getItem("bk_date");
    if (bkDate == null) {
      bkDate = "";
    }
    this.bkDate = bkDate;
  },
  methods: {
    outputDB() {
      var score = JSON.parse(localStorage.getItem("score"));
      var members = JSON.parse(localStorage.getItem("members"));
      var teams = JSON.parse(localStorage.getItem("teams"));
      var score_settings = JSON.parse(localStorage.getItem("score_settings"));
      var outputJson = {
        score: score,
        members: members,
        teams: teams,
        score_settings: score_settings
      };
      this.output = JSON.stringify(outputJson);
    },
    onClickInputDB() {
      this.isFormValid = this.$refs.score_json_input_form.validate();
      if (!this.isFormValid) {
        return;
      }
      // this.title = "入力確認";
      // this.msg = " DBへ入力しますか？";
      // this.callbackConfirm = this.callbackInputDB;

      // this.showModalConfirm = true;

      this.dialogProp = {
        title: "入力確認",
        msg: "DBへ入力しますか？",
        positive: "OK",
        negative: "キャンセル",
        callback: this.callbackInputDB
      };
      this.$refs.confirm.open(this.dialogProp);
    },
    callbackInputDB(result) {
      if (!result) {
        return;
      }
      var inputJson = JSON.parse(this.modelInput);
      localStorage.setItem("score", JSON.stringify(inputJson.score));
      localStorage.setItem("members", JSON.stringify(inputJson.members));
      localStorage.setItem("teams", JSON.stringify(inputJson.teams));
      localStorage.setItem(
        "score_settings",
        JSON.stringify(inputJson.score_settings)
      );
      this.$emit("route-home");
    },
    onClickBackupDB() {
      // this.title = "DBバックアップ確認";
      // this.msg = " DBをバックアップしますか？";
      // this.callbackConfirm = this.callbackBackupDB;

      // this.showModalConfirm = true;
      this.dialogProp = {
        title: "DBバックアップ確認",
        msg: "DBをバックアップしますか？",
        positive: "OK",
        negative: "キャンセル",
        callback: this.callbackBackupDB
      };
      this.$refs.confirm.open(this.dialogProp);
    },
    callbackBackupDB(result) {
      if (!result) {
        return;
      }

      var d = new Date();
      console.log("バックアップ日時:" + d.toLocaleString());
      var bkDate = d.toLocaleString();
      this.bkDate = bkDate;

      var score = JSON.parse(localStorage.getItem("score"));
      var members = JSON.parse(localStorage.getItem("members"));
      var teams = JSON.parse(localStorage.getItem("teams"));
      var score_settings = JSON.parse(localStorage.getItem("score_settings"));
      localStorage.setItem("bk_date", bkDate);
      localStorage.setItem("score_bk", JSON.stringify(score));
      localStorage.setItem("members_bk", JSON.stringify(members));
      localStorage.setItem("teams_bk", JSON.stringify(teams));
      localStorage.setItem("score_settings_bk", JSON.stringify(score_settings));
    },
    onClickRestoreDB() {
      // this.title = "DBリストア確認";
      // this.msg = " DBをリストアしますか？";
      // this.callbackConfirm = this.callbackRestoreDB;

      // this.showModalConfirm = true;
      this.dialogProp = {
        title: "DBリストア確認",
        msg: "DBをリストアしますか？",
        positive: "OK",
        negative: "キャンセル",
        callback: this.callbackRestoreDB
      };
      this.$refs.confirm.open(this.dialogProp);
    },
    callbackRestoreDB(result) {
      if (!result) {
        return;
      }

      var score = JSON.parse(localStorage.getItem("score_bk"));
      var members = JSON.parse(localStorage.getItem("members_bk"));
      var teams = JSON.parse(localStorage.getItem("teams_bk"));
      var score_settings = JSON.parse(
        localStorage.getItem("score_settings_bk")
      );
      localStorage.setItem("score", JSON.stringify(score));
      localStorage.setItem("members", JSON.stringify(members));
      localStorage.setItem("teams", JSON.stringify(teams));
      localStorage.setItem("score_settings", JSON.stringify(score_settings));

      this.$emit("route-home");
    },
    // result(flg) {
    //   this.callbackConfirm(flg);
    //   this.showModalConfirm = false;
    // }
    onClickClear() {
      this.dialogProp = {
        title: "DB消去確認",
        msg: "DBのデータを消去しますか？",
        positive: "OK",
        negative: "キャンセル",
        callback: this.callbackClear
      };
      this.$refs.confirm.open(this.dialogProp);
    },
    callbackClear(result) {
      if (!result) {
        return;
      }

      localStorage.setItem("score", JSON.stringify([]));
      localStorage.setItem("members", JSON.stringify([]));
      localStorage.setItem("teams", JSON.stringify([]));
      localStorage.setItem("score_settings", JSON.stringify({}));
    }
  }
};
</script>

<style src="../../style/style.css" lang="css">
